function localDateISO(date=new Date()){const y=date.getFullYear(),m=String(date.getMonth()+1).padStart(2,'0'),d=String(date.getDate()).padStart(2,'0');return `${y}-${m}-${d}`}
function todayISO(){return localDateISO()}
function currentMonthISO(){return todayISO().slice(0,7)}
function currentMonthStartISO(){const d=new Date();d.setDate(1);return localDateISO(d)}
function addDaysISO(dateText,days){const d=new Date(dateText+'T00:00:00');d.setDate(d.getDate()+days);return localDateISO(d)}
function dateDefaultForMonth(month=currentMonthISO()){return month===currentMonthISO()?todayISO():`${month}-01`}
function dateRangeKey(startId,endId){return `${startId}:${endId}`}
function setDateRangeDefault(startId,endId,force=false){const start=$(startId),end=$(endId);if(!start||!end)return;const key=dateRangeKey(startId,endId);if(!force&&dateFilterUi.dateRanges.has(key))return;const range={start:currentMonthStartISO(),end:todayISO()};start.value=range.start;end.value=range.end}
function setMonthDefault(id,force=false){const el=$(id);if(!el)return;if(!force&&dateFilterUi.months.has(id))return;el.value=currentMonthISO()}
function seedDefaultDateFilters(force=false){[['orderStart','orderEnd'],['financeStart','financeEnd'],['posStart','posEnd']].forEach(([start,end])=>setDateRangeDefault(start,end,force));setProductionDefaultDateRange(force);['commissionMonth','payrollMonth','budgetMonth'].forEach(id=>setMonthDefault(id,force))}
function bindDefaultDateFilters(){if(dateFilterUi.initialized)return;dateFilterUi.initialized=true;[['orderStart','orderEnd'],['financeStart','financeEnd'],['posStart','posEnd']].forEach(([startId,endId])=>{[startId,endId].forEach(id=>{const el=$(id);if(el)['input','change'].forEach(evt=>el.addEventListener(evt,()=>dateFilterUi.dateRanges.add(dateRangeKey(startId,endId))))})});['commissionMonth','payrollMonth','budgetMonth'].forEach(id=>{const el=$(id);if(el)['input','change'].forEach(evt=>el.addEventListener(evt,()=>dateFilterUi.months.add(id)))})}
function getDateRangeValues(startId,endId){setDateRangeDefault(startId,endId,false);return {start:$(startId)?.value||currentMonthStartISO(),end:$(endId)?.value||todayISO()}}
function getMonthValue(id){setMonthDefault(id,false);return $(id)?.value||currentMonthISO()}
function resetProductionEntriesCollapse(){productionUi.entriesExpanded=false}
function resetProductionDateRangeState(){productionUi.dateRangeTouched=false;setProductionDefaultDateRange(true);resetProductionEntriesCollapse()}
function setProductionDefaultDateRange(force=false){const start=$('prodStart'),end=$('prodEnd');if(!start||!end)return;if(!force&&productionUi.dateRangeTouched)return;start.value=currentMonthStartISO();end.value=todayISO()}
function preferredProductionBranch(filterId='prodBranch'){const selected=$(filterId)?.value;if(selected&&selected!=='All')return selected;if(state.user?.branch&&state.user.branch!=='All')return state.user.branch;const first=(availableBranches?.()||state.branches||[]).find(b=>b&&b.name);return first?.name||selected||''}

async function api(path,options={}){const opts={credentials:'same-origin',...options};if(opts.body&&typeof opts.body!=='string'){opts.headers={...(opts.headers||{}),'Content-Type':'application/json'};opts.body=JSON.stringify(opts.body)}const res=await fetch(path,opts);const ct=res.headers.get('content-type')||'';if(!res.ok){let msg=`Request failed (${res.status})`;if(ct.includes('json')){const d=await res.json();msg=d.error||msg}if(res.status===401){showLogin()}throw new Error(msg)}return ct.includes('json')?res.json():res}
function toast(message,error=false){const el=$('toast');el.textContent=message;el.classList.toggle('error',error);el.classList.add('show');setTimeout(()=>el.classList.remove('show'),2600)}
function initials(name){return name.split(/\s+/).filter(Boolean).map(x=>x[0]).slice(0,2).join('').toUpperCase()}
function has(p){return state.permissions.has(p)}
function showLogin(){state.user=null;$('appShell').classList.add('hidden');$('loginScreen').style.display='grid'}
function showApp(){ $('loginScreen').style.display='none';$('appShell').classList.remove('hidden') }

$('loginForm').addEventListener('submit',async e=>{e.preventDefault();$('loginError').textContent='';const f=new FormData(e.target);try{const d=await api('/api/login',{method:'POST',body:{username:f.get('username'),password:f.get('password')}});await initialize(d.user)}catch(err){$('loginError').textContent=err.message}});
