function applyDemoBanner(profile){const banner=$('cloudDemoBanner');if(banner){banner.textContent=profile.demo_banner_text;banner.classList.toggle('hidden',!profile.demo_mode);}const status=$('demoStatusPill');if(status){status.textContent=profile.demo_mode?'Demo Mode Active':'Client Mode Active';status.classList.toggle('hidden',!profile.demo_mode);}const accounts=$('demoAccountsBlock');if(accounts)accounts.classList.toggle('hidden',!profile.demo_mode);}
function applyCompanyBranding(info){const profile=normalizeCompanyProfile(info);state.companyProfile=profile;const name=profile.company_name;const subtitle=profile.company_subtitle;_companyName=name;_companySubtitle=subtitle;const display=name||'Company Dashboard';const displaySubtitle=subtitle||'CFO & Production';document.querySelectorAll('[data-company-name]').forEach(el=>{el.textContent=display;});document.querySelectorAll('[data-company-subtitle]').forEach(el=>{el.textContent=displaySubtitle;});document.title=`${display} - ${displaySubtitle}`;applyCompanyTagline();applyDemoBanner(profile);applyCurrencyLabels();const v=info.company_logo_updated||Date.now();const src='/api/company/logo?v='+encodeURIComponent(v);document.querySelectorAll('.brand-logo,.topbar-logo').forEach(img=>{img.src=src;});}
function applyCompanyTagline(){const name=_companyName;const key=name?'Sign in to the {company} management application.':'Sign in to the management application.';const tpl=window.I18N?I18N.t(key):key;const text=tpl.replace('{company}',name);document.querySelectorAll('[data-company-tagline]').forEach(el=>{el.textContent=text;});}
function applyUserLanguage(){if(!window.I18N||!state.user)return;I18N.setLanguage(state.user.language||I18N.getLanguage(),{persistLocal:true});}
async function persistUserLanguage(lang){if(!state.user)return;try{await api('/api/me/language',{method:'POST',body:{language:lang}});state.user.language=lang;}catch(e){}}
document.addEventListener('change',e=>{const el=e.target.closest&&e.target.closest('[data-i18n-switch]');if(!el||!window.I18N)return;const lang=el.value;I18N.setLanguage(lang,{persistLocal:true});persistUserLanguage(lang);});
/* ---- Settings module: tabs, company profile, owner settings (Phase 3.6) ---- */
let _settingsTabsReady=false;
function setupSettingsTabs(){
  if(_settingsTabsReady)return;_settingsTabsReady=true;
  document.querySelectorAll('#settingsTabs .settings-tab').forEach(btn=>{
    btn.addEventListener('click',()=>{
      document.querySelectorAll('#settingsTabs .settings-tab').forEach(b=>b.classList.remove('active'));
      document.querySelectorAll('.settings-panelgroup').forEach(p=>p.classList.remove('active'));
      btn.classList.add('active');
      const panel=document.querySelector(`.settings-panelgroup[data-settings-content="${btn.dataset.settingsTab}"]`);
      if(panel)panel.classList.add('active');
    });
  });
}
async function loadSettings(){
  if(window.I18N)syncLanguageControls();
  setupSettingsTabs();
  try{const d=await api('/api/settings');const sel=$('companyDefaultLanguage');if(sel&&d&&d.default_language)sel.value=d.default_language;}catch(e){}
  if(has('company_settings_read')){
    await Promise.all([loadCompanyProfile(),loadBranchManagement(),loadCompanyTargets()]);
    renderOwnerSettingsTables();
  }
}
