async function loadCompanyProfile(){try{const d=await api('/api/company/profile');const p=normalizeCompanyProfile(d.profile||{});const f=$('companyProfileForm');if(!f)return;f.elements.company_name.value=p.company_name||'';f.elements.company_subtitle.value=p.company_subtitle||'';f.elements.currency_label.value=p.currency_label||DEFAULT_COMPANY_PROFILE.currency_label;f.elements.company_vat.value=p.company_vat||'';f.elements.company_phone.value=p.company_phone||'';f.elements.company_email.value=p.company_email||'';f.elements.company_website.value=p.company_website||'';f.elements.company_address.value=p.company_address||'';f.elements.demo_mode.checked=!!p.demo_mode;f.elements.demo_banner_text.value=p.demo_banner_text||DEFAULT_COMPANY_PROFILE.demo_banner_text;applyCompanyBranding(d.profile||{});_companyLogoData=null;_companyLogoMime=null;_companyLogoRemove=false;const img=$('companyLogoPreview'),empty=$('companyLogoEmpty');const hasLogo=!!p.has_custom_logo;if(img){img.classList.toggle('hidden',!hasLogo);if(hasLogo)img.src='/api/company/logo?v='+encodeURIComponent(p.company_logo_updated||Date.now());}if(empty)empty.classList.toggle('hidden',hasLogo);}catch(e){}}
{const li=$('companyLogoInput');if(li)li.addEventListener('change',e=>{const file=e.target.files&&e.target.files[0];if(!file)return;if(file.size>2*1024*1024){toast('Logo must be 2 MB or smaller',true);li.value='';return;}const reader=new FileReader();reader.onload=()=>{_companyLogoData=reader.result;_companyLogoMime=file.type;_companyLogoRemove=false;const img=$('companyLogoPreview'),empty=$('companyLogoEmpty');if(img){img.src=reader.result;img.classList.remove('hidden');}if(empty)empty.classList.add('hidden');};reader.readAsDataURL(file);});}
{const cpf=$('companyProfileForm');if(cpf)cpf.addEventListener('submit',async e=>{e.preventDefault();const f=new FormData(e.target);const body={company_name:f.get('company_name'),company_subtitle:f.get('company_subtitle'),currency_label:f.get('currency_label'),company_vat:f.get('company_vat'),company_phone:f.get('company_phone'),company_email:f.get('company_email'),company_website:f.get('company_website'),company_address:f.get('company_address'),demo_mode:e.target.elements.demo_mode.checked,demo_banner_text:f.get('demo_banner_text')};if(_companyLogoRemove)body.remove_logo=true;else if(_companyLogoData){body.logo_data=_companyLogoData;body.logo_mime=_companyLogoMime;}try{const d=await api('/api/company/profile',{method:'POST',body});toast('Company profile saved');_companyLogoData=null;_companyLogoRemove=false;const li=$('companyLogoInput');if(li)li.value='';if(d.profile)applyCompanyBranding(d.profile);}catch(err){toast(err.message,true);}});}
