async function initialize(user=null){try{bindDefaultDateFilters();dateFilterUi.dateRanges.clear();dateFilterUi.months.clear();resetProductionDateRangeState();seedDefaultDateFilters(true);if(!user){const d=await api('/api/me');user=d.user}state.user=user;state.permissions=new Set(user.permissions||[]);showApp();applyUserUI();applyUserLanguage();await loadReferenceData();await Promise.all([loadDashboard(),loadEmployees()]);if(has('orders_read'))await loadOrders();if(has('membership_read'))await loadMembership();if(has('production_read'))await loadProduction();if(has('finance_read')){await loadFinance();await loadPosSales()}if(has('alert_read'))await loadNotifications();setupNavigation()}catch(err){console.error(err);showLogin()}}

