async function loadReferenceData(){const calls=[api('/api/branches'),api('/api/employees?branch=All')];if(has('budget_read'))calls.push(api('/api/budget/categories'));const results=await Promise.all(calls),b=results[0],e=results[1];state.branches=b.branches;state.activities=e.activities||[];state.employeeDirectory=e.employees;state.employees=e.employees;if(results[2])state.budget.categories=results[2].categories||[];fillBranchSelects();fillEmployeeSelects();fillFinanceCategoryOptions()}
function availableBranches(){return state.user.branch==='All'?state.branches.filter(b=>b.name!=='Nizwa'||true):state.branches.filter(b=>b.name===state.user.branch)}
function fillSelect(select,items,allLabel=null){const current=select.value;select.innerHTML=(allLabel?`<option value="All">${allLabel}</option>`:'')+items.map(x=>`<option value="${x.name}">${x.name}</option>`).join('');if([...select.options].some(o=>o.value===current))select.value=current}
function fillBranchSelects(){const branches=availableBranches();fillSelect($('globalBranch'),branches,state.user.branch==='All'?'All Branches':null);fillSelect($('orderBranch'),branches,state.user.branch==='All'?'All Branches':null);fillSelect($('membershipBranch'),branches,state.user.branch==='All'?'All Branches':null);fillSelect($('prodBranch'),branches,state.user.branch==='All'?'All Branches':null);fillSelect($('financeBranch'),branches,state.user.branch==='All'?'All Branches':null);fillSelect($('posBranch'),branches,state.user.branch==='All'?'All Branches':null);if($('posImportBranchOverride')){$('posImportBranchOverride').innerHTML='<option value="Auto Detect">Auto Detect</option>'+branches.map(x=>`<option value="${x.name}">${x.name}</option>`).join('')}fillSelect($('payrollBranch'),branches,state.user.branch==='All'?'All Branches':null);fillSelect($('budgetBranch'),branches,state.user.branch==='All'?'All Branches':null);fillSelect($('alertBranch'),branches,state.user.branch==='All'?'All Branches':null);fillSelect($('alertSettingsBranch'),[{name:'All'},...branches]);fillSelect($('attendanceBranchSelect'),branches);fillSelect($('orderEntryBranch'),branches);fillSelect($('membershipCardBranch'),branches);fillSelect($('customerBranchSelect'),branches);fillSelect($('productionEntryBranch'),branches);fillSelect($('readyCompletedBranch'),branches);fillSelect($('financeEntryBranch'),branches);fillSelect($('employeeBranchSelect'),branches);fillSelect($('userBranchSelect'),[{name:'All'},...state.branches]);if(state.user.branch!=='All'){['globalBranch','orderBranch','membershipBranch','prodBranch','financeBranch','payrollBranch','budgetBranch','alertBranch','attendanceBranchSelect','orderEntryBranch','membershipCardBranch','customerBranchSelect','productionEntryBranch','readyCompletedBranch','financeEntryBranch','employeeBranchSelect','posBranch'].forEach(id=>{$(id).value=state.user.branch;$(id).disabled=!['orderEntryBranch','membershipCardBranch','customerBranchSelect','productionEntryBranch','readyCompletedBranch','financeEntryBranch','employeeBranchSelect'].includes(id)})}if(state.user.branch!=='All'&&$('posImportBranchOverride')){$('posImportBranchOverride').value=state.user.branch;$('posImportBranchOverride').disabled=true}fillOrderEmployees()}
function fillEmployeeSelects(){const filtered=employeeListForBranch($('prodBranch').value).filter(e=>(e.categories||[]).length);$('prodEmployee').innerHTML='<option value="">All Employees</option>'+filtered.map(e=>`<option value="${e.id}">${e.name}</option>`).join('');fillProductionEntryEmployees()}
function employeeListForBranch(branch){return state.employeeDirectory.filter(e=>branch==='All'||!branch||e.branch===branch)}
function fillProductionEntryEmployees(){const branch=$('productionEntryBranch').value;const current=$('productionEntryEmployee').value;const list=employeeListForBranch(branch).filter(e=>(e.categories||[]).length);$('productionEntryEmployee').innerHTML=list.map(e=>`<option value="${e.id}">${e.name} — ${e.role}</option>`).join('');if([...$('productionEntryEmployee').options].some(o=>o.value===current))$('productionEntryEmployee').value=current;fillProductionActivities()}
function fillProductionActivities(preferred='',forceSingle=false){const employee=state.employeeDirectory.find(e=>String(e.id)===$('productionEntryEmployee').value);const activities=employee?.categories?.length?employee.categories:state.activities;const current=preferred||$('productionActivity').value;const paired=!forceSingle&&activities.includes('Body')&&activities.includes('Joint/Side');$('productionPairFields').classList.toggle('hidden',!paired);$('productionSingleFields').classList.toggle('hidden',paired);$('productionActivity').innerHTML=activities.map(a=>`<option value="${a}">${a}</option>`).join('');if(activities.includes(current))$('productionActivity').value=current;$('productionForm').dataset.paired=paired?'1':'0';updateProductionPreview()}

function setupNavigation(){const meta={dashboard:['Executive Dashboard','Company-wide financial and production overview'],alerts:['Alerts & Control','Daily management summary, actionable alerts and editable thresholds'],orders:['Orders & Delivery','Customer booking, production status and delivery tracking'],membership:['Membership & CRM','Customer cards, wallet balances, validity and usage'],production:['Production Report','Live employee and workshop production tracking'],financials:['Financial Entries','Income and expense transaction register'],posSales:['Sales Record','Imported invoice, customer, payment and due details'],employees:['Employees','Production performance by employee'],payroll:['Payroll & Attendance','Editable monthly salary and daily attendance control'],budget:['Budgets & Control','Editable monthly targets, limits and variance analysis'],reports:['Report Center','Management exports and database backup'],audit:['Audit Log','Every create, edit, delete and login activity'],users:['Users & Roles','Access control and branch permissions'],settings:['Settings','Language and application preferences']};document.querySelectorAll('.nav-item:not(.hidden)').forEach(btn=>btn.onclick=async()=>{document.querySelectorAll('.nav-item').forEach(x=>x.classList.remove('active'));document.querySelectorAll('.page').forEach(x=>x.classList.remove('active'));btn.classList.add('active');$(btn.dataset.page).classList.add('active');$('pageTitle').textContent=meta[btn.dataset.page][0];$('pageSubtitle').textContent=meta[btn.dataset.page][1];$('sidebar').classList.remove('open');if(btn.dataset.page==='dashboard'){await loadDashboard();setTimeout(drawChart,30)}if(btn.dataset.page==='alerts')await loadNotifications();if(btn.dataset.page==='orders')await loadOrders();if(btn.dataset.page==='membership')await loadMembership();if(btn.dataset.page==='production')await loadProduction();if(btn.dataset.page==='financials')await loadFinance();if(btn.dataset.page==='posSales')await loadPosSales();if(btn.dataset.page==='employees')await loadEmployees();if(btn.dataset.page==='payroll')await loadPayrollAndAttendance();if(btn.dataset.page==='budget')await loadBudget();if(btn.dataset.page==='audit')await loadAudit();if(btn.dataset.page==='users')await loadUsers();if(btn.dataset.page==='settings')await loadSettings()})}
$('menuBtn').onclick=()=>$('sidebar').classList.toggle('open');$('userMenuBtn').onclick=()=> $('userDropdown').classList.toggle('open');document.addEventListener('click',e=>{if(!e.target.closest('.user-menu-wrap'))$('userDropdown').classList.remove('open')});

async function loadDashboard(){const branch=$('globalBranch').value||'All';const d=await api(`/api/dashboard?branch=${encodeURIComponent(branch)}`);state.dashboard=d;renderDashboard()}
function renderDashboard(){const d=state.dashboard,c=d.current;let cards;if(d.can_see_finance){cards=[['Current MTD Income',money(c.income),'June 1–10 live entries','positive'],['Current MTD Expenses',money(c.expenses),'Expense control monitoring','negative'],['Current Net Profit',money(c.profit),`${pct(c.profit,c.income)} margin`,c.profit>=0?'positive':'negative'],['Current Produced Pcs',num(c.ready_pcs).toLocaleString(),'Formula-based production output','positive'],['Pending Orders',num(c.pending_orders).toLocaleString(),'Active customer orders',''],['Ready Orders',num(c.ready_orders).toLocaleString(),'Waiting for delivery','positive'],['Overdue Orders',num(c.overdue_orders).toLocaleString(),'Past due and not delivered',num(c.overdue_orders)?'negative':'positive'],['Delivered Orders',num(c.delivered_orders).toLocaleString(),'Completed deliveries','positive']]}else{cards=[['Current Produced Pcs',num(c.ready_pcs).toLocaleString(),'Formula-based production output','positive'],['Pending Orders',num(c.pending_orders).toLocaleString(),'Active customer orders',''],['Ready Orders',num(c.ready_orders).toLocaleString(),'Waiting for delivery','positive'],['Overdue Orders',num(c.overdue_orders).toLocaleString(),'Past due and not delivered',num(c.overdue_orders)?'negative':'positive']]}
 if(has('membership_read')){cards.push(['Active Cards',num(c.active_membership_cards).toLocaleString(),'Current membership portfolio','positive']);cards.push(d.can_see_finance?['Card Wallet Liability',money(c.membership_wallet_outstanding),'Unused customer card balance','']:['Expiring Cards',num(c.expiring_membership_cards).toLocaleString(),'Expiring within 30 days',num(c.expiring_membership_cards)?'negative':'positive'])}
 $('dashboardKpis').innerHTML=cards.map(c=>`<div class="kpi-card"><div class="kpi-label">${c[0]}</div><div class="kpi-value">${c[1]}</div><div class="kpi-note ${c[3]}">${c[2]}</div></div>`).join('');
 $('monthlyTableBody').innerHTML=d.monthly.map((r,i)=>{const profit=d.can_see_finance?num(r.income)-num(r.expenses):0;return `<tr><td>${r.month}</td>${d.can_see_finance?`<td>${money(r.income)}</td><td>${money(r.expenses)}</td><td class="status-profit">${money(profit)}</td><td>${pct(profit,r.income)}</td>`:''}<td>${num(r.ready_pcs).toLocaleString()}</td><td><span class="status-badge ${i===d.monthly.length-1?'active':''}">${i===d.monthly.length-1?'Live':'Locked'}</span></td></tr>`}).join('');
 if(d.can_see_finance){const max=Math.max(1,...d.branches.map(x=>num(x.income)));$('branchBars').innerHTML=d.branches.map(x=>`<div class="branch-row"><div class="meta"><span>${x.branch}</span><strong>${money(x.income)}</strong></div><div class="bar"><i style="width:${num(x.income)/max*100}%"></i></div><small style="color:var(--muted)">Expenses ${money(x.expenses)}</small></div>`).join('')}
 drawChart();
}
function drawChart(){const canvas=$('performanceChart');if(!canvas||!state.dashboard)return;const d=state.dashboard,mode=$('chartMetric').value;const ratio=window.devicePixelRatio||1,w=canvas.clientWidth||850,h=canvas.clientHeight||300;canvas.width=w*ratio;canvas.height=h*ratio;const ctx=canvas.getContext('2d');ctx.scale(ratio,ratio);ctx.clearRect(0,0,w,h);const pad={l:48,r:20,t:18,b:42},cw=w-pad.l-pad.r,ch=h-pad.t-pad.b;const values=mode==='financial'&&d.can_see_finance?d.monthly.flatMap(x=>[num(x.income),num(x.expenses)]):d.monthly.map(x=>num(x.ready_pcs));const max=Math.max(1,...values)*1.12;ctx.strokeStyle='rgba(255,255,255,.08)';ctx.fillStyle='#8e9aaa';ctx.font='10px DM Sans';for(let i=0;i<=4;i++){const y=pad.t+ch*i/4;ctx.beginPath();ctx.moveTo(pad.l,y);ctx.lineTo(w-pad.r,y);ctx.stroke();const v=max*(1-i/4);ctx.fillText(mode==='financial'?`${Math.round(v/1000)}k`:Math.round(v),5,y+3)}const group=cw/d.monthly.length;d.monthly.forEach((row,i)=>{const x=pad.l+i*group;ctx.fillStyle='#98a3b2';ctx.textAlign='center';ctx.fillText(row.month.split(' ')[0],x+group/2,h-13);if(mode==='financial'&&d.can_see_finance){const bw=Math.min(24,group*.25),h1=num(row.income)/max*ch,h2=num(row.expenses)/max*ch;ctx.fillStyle='#d5b36b';ctx.fillRect(x+group*.5-bw-2,pad.t+ch-h1,bw,h1);ctx.fillStyle='#6c7890';ctx.fillRect(x+group*.5+2,pad.t+ch-h2,bw,h2)}else{const bw=Math.min(36,group*.45),bh=num(row.ready_pcs)/max*ch;ctx.fillStyle='#d5b36b';ctx.fillRect(x+group*.5-bw/2,pad.t+ch-bh,bw,bh)}});ctx.textAlign='left';$('chartTitle').textContent=mode==='financial'&&d.can_see_finance?'Income vs Expenses':'Produced Pcs Trend'}
$('chartMetric').onchange=drawChart;window.addEventListener('resize',drawChart);$('refreshDashboard').onclick=async()=>{await loadDashboard();toast('Dashboard refreshed')};$('globalBranch').onchange=async()=>{const b=$('globalBranch').value;if([...$('orderBranch').options].some(o=>o.value===b))$('orderBranch').value=b;if([...$('membershipBranch').options].some(o=>o.value===b))$('membershipBranch').value=b;if([...$('prodBranch').options].some(o=>o.value===b))$('prodBranch').value=b;if([...$('financeBranch').options].some(o=>o.value===b))$('financeBranch').value=b;if([...$('posBranch').options].some(o=>o.value===b))$('posBranch').value=b;if([...$('payrollBranch').options].some(o=>o.value===b))$('payrollBranch').value=b;if([...$('budgetBranch').options].some(o=>o.value===b))$('budgetBranch').value=b;if([...$('alertBranch').options].some(o=>o.value===b))$('alertBranch').value=b;fillEmployeeSelects();await Promise.all([loadDashboard(),loadEmployees()]);if(has('orders_read'))await loadOrders();if(has('membership_read'))await loadMembership();if(has('production_read'))await loadProduction();if(has('finance_read')){await loadFinance();await loadPosSales()}if(has('attendance_read'))await loadPayrollAndAttendance();if(has('budget_read'))await loadBudget();if(has('alert_read'))await loadNotifications()};


async function loadOrders(){const range=getDateRangeValues('orderStart','orderEnd');const p=new URLSearchParams({branch:$('orderBranch').value||'All',status:$('orderStatus').value||'All',start:range.start,end:range.end,search:$('orderSearch').value.trim()});const d=await api('/api/orders?'+p);state.orders=d;state.orderStatuses=d.statuses||[];state.orderItemTypes=d.item_types||[];fillOrderReferenceSelects();renderOrders()}
function fillOrderReferenceSelects(){const currentStatus=$('orderStatus').value||'All';$('orderStatus').innerHTML='<option value="All">All Statuses</option>'+state.orderStatuses.map(s=>`<option>${s}</option>`).join('');if(state.orderStatuses.includes(currentStatus))$('orderStatus').value=currentStatus;$('orderEntryStatus').innerHTML=state.orderStatuses.map(s=>`<option>${s}</option>`).join('');$('orderItemType').innerHTML=state.orderItemTypes.map(s=>`<option>${s}</option>`).join('')}
function fillOrderEmployees(preferred=''){if(!$('orderAssignedEmployee'))return;const branch=$('orderEntryBranch').value;const current=preferred||$('orderAssignedEmployee').value;let list=employeeListForBranch(branch);if(branch==='Nizwa')list=state.employeeDirectory;$('orderAssignedEmployee').innerHTML='<option value="">Unassigned</option>'+list.map(e=>`<option value="${e.id}">${e.name} — ${e.branch} / ${e.role}</option>`).join('');if([...$('orderAssignedEmployee').options].some(o=>o.value===String(current)))$('orderAssignedEmployee').value=String(current)}
function orderStatusClass(status){return 'order-status status-'+status.toLowerCase().replaceAll('/','-').replaceAll(' ','-')}
function renderOrders(){const d=state.orders,s=d.summary||{};$('orderKpis').innerHTML=[['Total Orders',num(s.total),'Selected date range'],['Pending',num(s.pending),'Active workflow'],['Ready',num(s.ready),'Waiting for delivery'],['Overdue',num(s.overdue),'Past due date']].map((c,i)=>`<div class="kpi-card"><div class="kpi-label">${c[0]}</div><div class="kpi-value">${c[1]}</div><div class="kpi-note ${i===3&&num(s.overdue)?'negative':''}">${c[2]}</div></div>`).join('');$('ordersTableBody').innerHTML=(d.orders||[]).map(r=>`<tr class="${r.overdue?'overdue-row':''}"><td><strong>${r.order_no}</strong></td><td>${r.booking_date}</td><td>${r.due_date}${r.overdue?' <span class="overdue-label">Overdue</span>':''}</td><td>${r.customer_name}</td><td>${r.phone||'—'}</td><td>${r.branch}</td><td>${r.item_type} × ${r.quantity}</td><td>${r.assigned_employee||'Unassigned'}</td><td><span class="${orderStatusClass(r.status)}">${r.status}</span></td>${d.can_see_finance?`<td>${money(r.total_amount)}</td><td>${money(r.advance_amount)}</td><td class="${num(r.balance_amount)>0?'status-expense':'status-profit'}">${money(r.balance_amount)}</td>`:''}${d.can_write?`<td><button class="action-btn" onclick="editOrder(${r.id})">Edit</button>${d.can_delete?`<button class="action-btn delete" onclick="deleteOrder(${r.id})">Delete</button>`:''}</td>`:''}</tr>`).join('')||'<tr><td colspan="13">No orders found for this filter.</td></tr>';applyUserUI()}
$('orderBranch').onchange=loadOrders;$('orderStatus').onchange=loadOrders;$('applyOrderFilter').onclick=loadOrders;$('orderSearch').onkeydown=e=>{if(e.key==='Enter')loadOrders()};


async function loadMembership(){const p=new URLSearchParams({branch:$('membershipBranch').value||'All',status:$('membershipStatus').value||'All',search:$('membershipSearch').value.trim()});const branch=$('membershipBranch').value||'All';const cp=new URLSearchParams({branch,month:getMonthValue('commissionMonth')});const [m,c,comm]=await Promise.all([api('/api/membership?'+p),api(`/api/customers?branch=${encodeURIComponent(branch)}&search=${encodeURIComponent($('membershipSearch').value.trim())}`),api('/api/membership/commissions?'+cp)]);state.membership=m;state.customers=c.customers||[];state.commissions=comm;state.membershipStatuses=m.statuses||[];state.membershipTransactionTypes=m.transaction_types||[];fillMembershipReferences();renderMembership()}
function fillMembershipReferences(){const current=$('membershipStatus').value||'All';$('membershipStatus').innerHTML='<option value="All">All Statuses</option>'+state.membershipStatuses.map(x=>`<option>${x}</option>`).join('');if(state.membershipStatuses.includes(current))$('membershipStatus').value=current;$('membershipCardStatus').innerHTML=state.membershipStatuses.map(x=>`<option>${x}</option>`).join('');$('membershipTransactionType').innerHTML=state.membershipTransactionTypes.map(x=>`<option>${x}</option>`).join('');const plans=(state.membership.plans||[]).filter(x=>x.active);$('membershipPlanSelect').innerHTML=plans.map(x=>`<option value="${x.id}">${x.name} — ${money(x.sale_price)} / Wallet ${money(x.wallet_balance)}</option>`).join('');fillMembershipCustomers();fillMembershipSalesAgents();renderMembershipPlansTable()}
function fillMembershipCustomers(preferred=''){const branch=$('membershipCardBranch').value;const current=String(preferred||$('membershipCustomerSelect').value||'');const list=state.customers.filter(x=>x.active&&(branch==='All'||x.branch===branch));$('membershipCustomerSelect').innerHTML='<option value="">Select customer</option>'+list.map(x=>`<option value="${x.id}">${x.name}${x.phone?' — '+x.phone:''}</option>`).join('');if([...$('membershipCustomerSelect').options].some(o=>o.value===current))$('membershipCustomerSelect').value=current}
function fillMembershipSalesAgents(preferred=''){const branch=$('membershipCardBranch').value;const list=state.employeeDirectory.filter(x=>x.active&&(branch==='All'||x.branch===branch));$('membershipSalesAgentList').innerHTML=list.map(x=>`<option value="${String(x.name).replaceAll('&','&amp;').replaceAll('\"','&quot;')}">${x.role} · ${x.branch}</option>`).join('');if(preferred!==undefined&&preferred!==null&&String(preferred)!=='')$('membershipSalesAgentName').value=String(preferred)}
function statusClass(status){return `status-badge ${status==='Active'?'active':status==='Expired'?'inactive':''}`}
function renderMembership(){const d=state.membership,s=d.summary||{};$('membershipKpis').innerHTML=[['Active Cards',num(s.active_cards),'Usable customer cards'],['Wallet Outstanding',d.can_see_finance?money(s.wallet_outstanding):'Restricted','Unused card balances'],['Expiring Soon',num(s.expiring_cards),'Within next 30 days'],['Total Commission',d.can_see_finance?money(s.total_commission):'Restricted','Commission on filtered cards']].map((c,i)=>`<div class="kpi-card"><div class="kpi-label">${c[0]}</div><div class="kpi-value">${c[1]}</div><div class="kpi-note ${i===2&&num(s.expiring_cards)?'negative':''}">${c[2]}</div></div>`).join('');$('membershipTableBody').innerHTML=(d.cards||[]).map(r=>`<tr><td><strong>${r.card_no}</strong></td><td>${r.customer_name}</td><td>${r.phone||'—'}</td><td>${r.plan_name}</td><td>${r.branch}</td><td>${r.sales_agent_display||r.sales_agent_name||'Direct sale'}</td><td>${r.issue_date}</td><td>${r.expiry_date}</td><td class="status-profit">${money(r.current_balance)}</td><td>${(r.sales_agent_display||r.sales_agent_name)?`${money(r.commission_amount)}<small class="table-sub">${num(r.commission_rate).toFixed(2)}%</small>`:'—'}</td><td><span class="${statusClass(r.status)}">${r.status}</span></td><td><button class="action-btn" onclick="viewMembershipHistory(${r.id})">History</button>${d.can_write&&r.status==='Active'?`<button class="action-btn" onclick="useMembershipCard(${r.id})">Use Card</button>`:''}${d.can_write?`<button class="action-btn" onclick="editMembershipCard(${r.id})">Edit</button>`:''}${d.can_delete?`<button class="action-btn delete" onclick="deleteMembershipCard(${r.id})">Delete</button>`:''}</td></tr>`).join('')||'<tr><td colspan="12">No membership cards found. Add a customer, then issue the first card.</td></tr>';renderCustomers();renderPlanCards();renderCommissions();applyUserUI()}
function renderCustomers(){$('customerCountLabel').textContent=`${state.customers.length} customers`;$('customerTableBody').innerHTML=state.customers.map(c=>`<tr><td><strong>${c.name}</strong><small class="table-sub">${c.email||''}</small></td><td>${c.phone||'—'}</td><td>${c.branch}</td><td>${c.card_count}</td><td>${money(c.active_balance)}</td>${has('membership_write')?`<td><button class="action-btn" onclick="editCustomer(${c.id})">Edit</button></td>`:''}</tr>`).join('')||'<tr><td colspan="6">No customers found.</td></tr>'}
function renderCommissions(){const d=state.commissions||{},s=d.summary||{};$('commissionKpis').innerHTML=[['Cards Sold',num(s.cards_sold),'Selected month'],['Sales Agents',num(s.agents),'Agents earning commission'],['Card Sales',d.can_see_finance?money(s.total_sales):'Restricted','Agent-attributed sales'],['Commission Payable',d.can_see_finance?money(s.total_commission):'Restricted','Add to monthly salary']].map(c=>`<div class="kpi-card"><div class="kpi-label">${c[0]}</div><div class="kpi-value">${c[1]}</div><div class="kpi-note">${c[2]}</div></div>`).join('');$('commissionTableBody').innerHTML=(d.rows||[]).map(r=>`<tr><td><strong>${r.sales_agent}</strong></td><td>${r.designation}</td><td>${r.branch}</td><td>${r.cards_sold}</td><td>${d.can_see_finance?money(r.total_sales):'Restricted'}</td><td class="status-profit">${d.can_see_finance?money(r.total_commission):'Restricted'}</td></tr>`).join('')||'<tr><td colspan="6">No agent-attributed card sales for this month.</td></tr>'}
function renderPlanCards(){$('membershipPlanCards').innerHTML=(state.membership.plans||[]).filter(x=>x.active).map(p=>`<div class="plan-card"><div><strong>${p.name}</strong><span>${p.validity_months} months · ${p.free_deliveries===-1?'Unlimited':p.free_deliveries} deliveries</span></div><div><b>${money(p.sale_price)}</b><small>Wallet ${money(p.wallet_balance)} · Benefit ${money(p.benefit_amount)}</small></div></div>`).join('')}
function renderMembershipPlansTable(){$('membershipPlansTableBody').innerHTML=(state.membership.plans||[]).map(p=>`<tr><td><strong>${p.name}</strong></td><td>${money(p.sale_price)}</td><td>${money(p.wallet_balance)}</td><td>${money(p.benefit_amount)}</td><td>${p.validity_months} months</td><td>${p.free_deliveries===-1?'Unlimited':p.free_deliveries}</td><td><span class="status-badge ${p.active?'active':'inactive'}">${p.active?'Active':'Inactive'}</span></td><td><button class="action-btn" onclick="editMembershipPlan(${p.id})">Edit</button></td></tr>`).join('')}
$('membershipBranch').onchange=loadMembership;$('membershipStatus').onchange=loadMembership;$('applyMembershipFilter').onclick=loadMembership;$('applyCommissionFilter').onclick=loadMembership;$('commissionMonth').onchange=loadMembership;$('membershipSearch').onkeydown=e=>{if(e.key==='Enter')loadMembership()};
$('addCustomerBtn').onclick=()=>{const f=$('customerForm');f.reset();f.elements.id.value='';f.elements.active.checked=true;f.elements.branch.value=state.user.branch==='All'?($('membershipBranch').value==='All'?'Al Khoud':$('membershipBranch').value):state.user.branch;$('customerModalTitle').textContent='Add Customer';openModal('customerModal')};
window.editCustomer=id=>{const c=state.customers.find(x=>x.id===id);if(!c)return;const f=$('customerForm');Object.keys(c).forEach(k=>{if(f.elements[k]&&k!=='active')f.elements[k].value=c[k]??''});f.elements.active.checked=!!c.active;$('customerModalTitle').textContent=`Edit ${c.name}`;openModal('customerModal')};
$('customerForm').onsubmit=async e=>{e.preventDefault();const f=new FormData(e.target),id=f.get('id');const body={name:f.get('name'),branch:f.get('branch'),phone:f.get('phone'),email:f.get('email'),address:f.get('address'),notes:f.get('notes'),active:e.target.elements.active.checked};try{await api(id?`/api/customers/${id}`:'/api/customers',{method:id?'PUT':'POST',body});closeModal('customerModal');await loadMembership();toast(id?'Customer updated':'Customer added')}catch(err){toast(err.message,true)}};
function applyPlanDefaults(){const p=(state.membership.plans||[]).find(x=>String(x.id)===$('membershipPlanSelect').value);const f=$('membershipCardForm');if(!p)return;if(!num(f.elements.sale_price.value))f.elements.sale_price.value=p.sale_price;if(!num(f.elements.opening_balance.value))f.elements.opening_balance.value=p.wallet_balance}
$('membershipPlanSelect').onchange=applyPlanDefaults;$('membershipCardBranch').onchange=()=>{fillMembershipCustomers();fillMembershipSalesAgents()};
