async function loadPosSales(){
  if(!has('finance_read')||!$('posBranch'))return;
  const range=getDateRangeValues('posStart','posEnd');
  const p=new URLSearchParams({branch:$('posBranch').value||'All',start:range.start,end:range.end,status:$('posStatus').value||'All',search:$('posSearch').value.trim()});
  const [sales,imports]=await Promise.all([api('/api/pos-sales?'+p),api('/api/pos-sales/imports')]);
  state.posSales.sales=sales.sales||[];state.posSales.summary=sales.summary||{};state.posSales.imports=imports.imports||[];renderPosSales();
}
function renderPosSales(){
  const s=state.posSales.summary||{};
  $('posKpis').innerHTML=[['Total Sales',money(s.total_amount),'Invoice value'],['Total Paid',money(s.total_paid),'Amount collected'],['Outstanding Due',money(s.sell_due),'Customer receivable'],['Invoices',num(s.invoice_count).toLocaleString(),`${num(s.customer_count)} customers`],['Total Items',num(s.total_items).toLocaleString(),'Items in selected range']].map(c=>`<div class="kpi-card"><div class="kpi-label">${c[0]}</div><div class="kpi-value">${c[1]}</div><div class="kpi-note">${c[2]}</div></div>`).join('');
  $('posSalesTableBody').innerHTML=(state.posSales.sales||[]).map(r=>`<tr><td>${esc(r.sale_datetime)}</td><td><strong>${esc(r.invoice_no)}</strong></td><td>${esc(r.customer_name||'Walk-in')}</td><td>${esc(r.contact_number||'—')}</td><td>${esc(r.branch)}</td><td><span class="status-badge ${String(r.payment_status).toLowerCase()==='paid'?'positive':String(r.payment_status).toLowerCase()==='due'?'negative':'warning'}">${esc(r.payment_status)}</span></td><td>${esc(r.payment_method||'Other')}</td><td>${money(r.total_amount)}</td><td class="status-profit">${money(r.total_paid)}</td><td class="${num(r.sell_due)>0?'status-expense':''}">${money(r.sell_due)}</td><td>${num(r.total_items)}</td><td>${esc(r.added_by||'—')}</td><td>${esc(r.sell_note||r.staff_note||'—')}</td>${has('finance_write')?`<td><button class="action-btn delete" onclick="deleteSalesRecord(${r.id})">Delete</button></td>`:''}</tr>`).join('')||`<tr><td colspan="${has('finance_write')?14:13}">No sales records found for this filter.</td></tr>`;
  $('posImportHistoryBody').innerHTML=(state.posSales.imports||[]).map(r=>`<tr><td>${esc(r.imported_at)}</td><td>${esc(r.file_name)}</td><td>${esc(r.branch_override)}</td><td>${r.rows_total}</td><td class="status-profit">${r.inserted_count}</td><td>${r.updated_count}</td><td>${r.unchanged_count}</td><td class="${r.invalid_count?'status-expense':''}">${r.invalid_count}</td><td>${r.customer_count}</td><td>${r.post_to_finance?esc(r.revenue_basis):'Details only'}</td><td>${esc(r.imported_by)}</td></tr>`).join('')||'<tr><td colspan="11">No sales imports recorded.</td></tr>';
  applyUserUI();
}
window.deleteSalesRecord=id=>{const r=(state.posSales.sales||[]).find(x=>x.id===id);if(!r)return;confirmAction('Delete sales record?',`Invoice ${r.invoice_no} for ${r.customer_name||'Walk-in Customer'} will be deleted. If it was posted to Financials, the linked income entry will also be removed. Customer profile and import history will remain.`,async()=>{const d=await api(`/api/pos-sales/${id}`,{method:'DELETE'});await Promise.all([loadPosSales(),loadFinance(),loadDashboard()]);if(has('alert_read'))await loadNotifications();toast(d.finance_deleted?'Sales record and linked financial entry deleted':'Sales record deleted')})};
function setPosImportBusy(busy,label='Import Sales'){
  const btn=$('confirmPosImportBtn');
  btn.disabled=busy;
  btn.textContent=busy?'Importing…':label;
  $('previewPosImportBtn').disabled=busy;
}
function resetPosImport(){
  const f=$('posImportForm');f.reset();state.posSales.preview=null;state.posSales.fileContentB64='';state.posSales.fileName='';$('posImportPreview').classList.add('hidden');setPosImportBusy(false);$('posImportErrors').classList.add('hidden');if($('posFileStatus'))$('posFileStatus').textContent='Choose a CSV or Excel XLSX file. Preview is optional; you can import directly.';if(state.user.branch!=='All'){$('posImportBranchOverride').value=state.user.branch;$('posImportBranchOverride').disabled=true}else{$('posImportBranchOverride').disabled=false;$('posImportBranchOverride').value='Auto Detect'}
}
async function readSelectedPosFile(){
  const file=$('posSalesFile').files[0];
  if(!file)throw new Error('Select the sales CSV or Excel file');
  const ext=(file.name.split('.').pop()||'').toLowerCase();
  if(!['csv','xlsx'].includes(ext))throw new Error('Select a .csv or .xlsx sales export');
  if(file.size>15_000_000)throw new Error('Sales file is larger than 15 MB');
  if($('posFileStatus'))$('posFileStatus').textContent=`Reading ${file.name}…`;
  const dataUrl=await new Promise((resolve,reject)=>{const reader=new FileReader();reader.onload=()=>resolve(reader.result);reader.onerror=()=>reject(new Error('The selected file could not be read'));reader.readAsDataURL(file)});
  state.posSales.fileContentB64=String(dataUrl).split(',')[1]||'';
  state.posSales.fileName=file.name;
  if(!state.posSales.fileContentB64)throw new Error('The selected file is empty or could not be read');
  if($('posFileStatus'))$('posFileStatus').textContent=`Ready: ${file.name} · ${(file.size/1024).toFixed(1)} KB`;
  return file;
}
function renderPosPreview(d){
  state.posSales.preview=d;$('posImportPreview').classList.remove('hidden');$('confirmPosImportBtn').disabled=!d.valid_rows;
  const s=d.summary||{};$('posPreviewKpis').innerHTML=[['Valid Invoices',d.valid_rows,`${d.new_invoices} new · ${d.existing_invoices} existing`],['Sales Value',money(s.total_amount),'Total Amount'],['Amount Paid',money(s.total_paid),'Collected'],['Outstanding Due',money(s.sell_due),'Receivable'],['Customers',s.customer_count,'Unique customer/phone']].map(c=>`<div class="kpi-card"><div class="kpi-label">${c[0]}</div><div class="kpi-value">${c[1]}</div><div class="kpi-note">${c[2]}</div></div>`).join('');
  $('posPreviewMeta').innerHTML=`<span><strong>Source:</strong> ${esc(d.source_format||'POS File')} · ${esc(d.file_name||'')}</span><span><strong>Branches:</strong> ${Object.entries(d.branches||{}).map(([k,v])=>`${esc(k)} (${v})`).join(', ')||'—'}</span><span><strong>Payment:</strong> ${Object.entries(d.payment_statuses||{}).map(([k,v])=>`${esc(k)} (${v})`).join(', ')||'—'}</span><span><strong>Duplicate rows inside file:</strong> ${d.duplicate_in_file||0}</span>`;
  $('posPreviewBody').innerHTML=(d.sample||[]).map(r=>`<tr><td>${esc(r.sale_datetime)}</td><td>${esc(r.invoice_no)}</td><td>${esc(r.customer_name)}</td><td>${esc(r.contact_number||'—')}</td><td>${esc(r.branch)}</td><td>${esc(r.payment_status)}</td><td>${money(r.total_amount)}</td><td>${money(r.total_paid)}</td><td>${money(r.sell_due)}</td><td>${r.total_items}</td></tr>`).join('');
  if((d.errors||[]).length){$('posImportErrors').classList.remove('hidden');$('posImportErrors').innerHTML=`<strong>${d.invalid_rows} invalid row(s) will be skipped:</strong><br>`+d.errors.map(e=>`Line ${e.line}: ${esc(e.invoice_no||'No invoice')} — ${esc(e.error)}`).join('<br>')}else $('posImportErrors').classList.add('hidden');
}
