function renderEmployees(){const query=($('employeeSearch')?.value||'').trim().toLowerCase();const list=state.employees.filter(e=>!query||`${e.name} ${e.role} ${e.branch} ${(e.categories||[]).join(' ')}`.toLowerCase().includes(query));$('employeeGrid').innerHTML=list.map(e=>{const achieved=Math.min(100,num(e.quantity)/Math.max(1,num(e.monthly_target))*100);const chips=(e.categories||[]).map(c=>`<span class="category-chip">${c}</span>`).join('');return `<article class="employee-card ${e.active?'':'inactive'}"><div class="employee-top"><div class="employee-avatar">${initials(e.name)}</div><div><h4>${e.name}</h4><p>${e.role} · ${e.branch}</p></div></div><div class="category-chips">${chips||'<span class="category-chip">No category</span>'}</div><div class="employee-stats"><div><span>Activity Qty</span><strong>${num(e.quantity)}</strong></div><div><span>Total Produced</span><strong>${num(e.ready_pcs)}</strong></div><div><span>OT Hours</span><strong>${num(e.ot_hours)}</strong></div></div><div class="progress"><i style="width:${achieved}%"></i></div><p>Monthly target: ${num(e.monthly_target)} · Achievement: ${achieved.toFixed(1)}%</p><div class="employee-actions"><button class="link-btn" onclick="openHistory(${e.id})">View History</button>${has('employee_write')?`<button class="action-btn" onclick="editEmployee(${e.id})">Edit Employee</button>`:''}<span class="status-badge ${e.active?'active':'inactive'}">${e.active?'Active':'Inactive'}</span></div></article>`}).join('')||'<article class="panel">No employees found for this filter.</article>'}

async function loadFinance(){const range=getDateRangeValues('financeStart','financeEnd');const p=new URLSearchParams({branch:$('financeBranch').value||'All',start:range.start,end:range.end});const d=await api('/api/finance?'+p);state.finance=d.entries;renderFinance()}
function renderFinance(){const income=state.finance.filter(x=>x.type==='Income').reduce((a,x)=>a+num(x.amount),0),expense=state.finance.filter(x=>x.type==='Expense').reduce((a,x)=>a+num(x.amount),0),profit=income-expense;$('financeKpis').innerHTML=[['Income',money(income),'Selected date range'],['Expenses',money(expense),'Selected date range'],['Net Position',money(profit),`${pct(profit,income)} margin`],['Transactions',state.finance.length,'Database entries']].map(c=>`<div class="kpi-card"><div class="kpi-label">${c[0]}</div><div class="kpi-value">${c[1]}</div><div class="kpi-note">${c[2]}</div></div>`).join('');$('financeTableBody').innerHTML=state.finance.map(r=>`<tr><td>${r.date}</td><td>${r.branch}</td><td class="${r.type==='Income'?'status-income':'status-expense'}">${r.type}</td><td>${r.category}</td><td>${r.description}</td><td>${r.payment_method}</td><td>${r.reference||'—'}</td><td>${money(r.amount)}</td><td>${r.entered_by}</td>${has('finance_write')?`<td><button class="action-btn" onclick="editFinance(${r.id})">Edit</button><button class="action-btn delete" onclick="deleteFinance(${r.id})">Delete</button></td>`:''}</tr>`).join('')||'<tr><td colspan="10">No financial entries found.</td></tr>';applyUserUI()}
$('financeBranch').onchange=loadFinance;$('applyFinanceFilter').onclick=loadFinance;

