function updateProductionPreview(){const f=$('productionForm'),paired=f.dataset.paired==='1';let produced=0,note='For Daraz, VIP Design, Iron and Cutting: 1 pc done = 1 pc produced.';if(paired){const body=num(f.elements.body_quantity.value),joint=num(f.elements.joint_quantity.value);produced=Math.min(body,joint);note=`${body} Body + ${joint} Joint/Side = ${produced} Full Body Produced`;}else{const activity=f.elements.activity.value,qty=num(f.elements.quantity.value);produced=['Body','Joint/Side'].includes(activity)?0:qty;note=['Body','Joint/Side'].includes(activity)?'Body and Joint/Side are paired in the Production Summary. Use the paired entry screen for daily body work.':'Formula: 1 pc done = 1 pc produced.';}$('productionProducedPreview').textContent=`${produced} pcs`;$('productionFormulaNote').textContent=note}
['body_quantity','joint_quantity','quantity'].forEach(name=>$('productionForm').elements[name]?.addEventListener('input',updateProductionPreview));
