async function loadUsers(){const d=await api('/api/users');state.users=d.users||[];state.roles=d.role_details||[];state.permissionCatalog=d.permission_catalog||[];$('userRoleSelect').innerHTML=(d.roles||[]).map(r=>`<option>${r}</option>`).join('');renderUsers();renderRoles()}
function renderUsers(){$('usersTableBody').innerHTML=state.users.map(u=>`<tr><td><strong>${u.username}</strong></td><td>${u.full_name}</td><td><span class="role-badge">${u.role}</span></td><td>${u.branch}</td><td><span class="status-badge ${u.active?'active':'inactive'}">${u.active?'Active':'Inactive'}</span></td><td>${u.created_at.split(' ')[0]}</td><td><button class="action-btn" onclick="editUser(${u.id})">Edit</button></td></tr>`).join('')}
