function renderAttendance(){$('attendanceTableBody').innerHTML=(state.attendance.rows||[]).map(r=>`<tr><td>${r.date}</td><td><strong>${r.employee_name}</strong><br><small>${r.role}</small></td><td>${r.branch}</td><td><span class="attendance-status ${r.status.toLowerCase().replaceAll(' ','-')}">${r.status}</span></td><td>${r.notes||''}</td><td>${r.entered_by}</td><td class="attendance-write">${has('attendance_write')?`<button class="danger-link" onclick="deleteAttendance(${r.id})">Delete</button>`:''}</td></tr>`).join('')||'<tr><td colspan="7">No attendance entries for this month.</td></tr>'}
function fillAttendanceReferences(){const branch=$('attendanceBranchSelect').value||($('payrollBranch').value==='All'?'Al Khoud':$('payrollBranch').value);const list=employeeListForBranch(branch).filter(e=>e.active);$('attendanceEmployeeSelect').innerHTML=list.map(e=>`<option value="${e.id}">${e.name} — ${e.role}</option>`).join('');$('attendanceStatusSelect').innerHTML=(state.attendance.statuses||[]).map(x=>`<option>${x}</option>`).join('')}
