/* Phase 3.3 — Advanced executive UI and analytics */
const ADVANCED_COLORS=['#e0b85f','#5f8fe8','#59c58f','#b68be8','#f07c73','#70c7d4','#d88c4a','#8290a8','#f1d690'];
const ADVANCED_GRID='rgba(255,255,255,.075)';
const ADVANCED_TEXT='#9aa9bc';
