function chartLegend(id,items){const el=$(id);if(!el)return;el.innerHTML=items.map((x,i)=>`<div class="legend-row luxury-legend"><span class="legend-dot" style="--legend-color:${x.color||ADVANCED_COLORS[i%ADVANCED_COLORS.length]};background:${x.color||ADVANCED_COLORS[i%ADVANCED_COLORS.length]}"></span><span>${esc(x.label)}</span><strong>${x.display??compactValue(x.value)}</strong></div>`).join('')}
