  const bg=ctx.createLinearGradient(x,y,x,y+h);bg.addColorStop(0,'rgba(24,43,69,.32)');bg.addColorStop(1,'rgba(5,12,22,.06)');ctx.fillStyle=bg;roundRectCanvas(ctx,x,y,w,h,14);ctx.fill();
  const glow=ctx.createRadialGradient(x+w*.76,y+h*.05,0,x+w*.76,y+h*.05,w*.72);glow.addColorStop(0,'rgba(224,184,95,.07)');glow.addColorStop(1,'rgba(224,184,95,0)');ctx.fillStyle=glow;roundRectCanvas(ctx,x,y,w,h,14);ctx.fill();
  ctx.strokeStyle='rgba(255,255,255,.035)';ctx.lineWidth=1;roundRectCanvas(ctx,x+.5,y+.5,w-1,h-1,14);ctx.stroke();
