  start=-Math.PI/2;
  clean.forEach((x,i)=>{const val=num(x.value),ang=val/total*Math.PI*2,color=x.color||ADVANCED_COLORS[i%ADVANCED_COLORS.length];const grad=ctx.createLinearGradient(cx-rx,cy-ry,cx+rx,cy+ry);grad.addColorStop(0,shadeColor(color,25));grad.addColorStop(.42,color);grad.addColorStop(1,shadeColor(color,-20));ctx.save();ctx.shadowColor=colorAlpha(color,.35);ctx.shadowBlur=10;drawEllipseArc(ctx,cx,cy,rx,ry,start+gap,start+ang-gap,grad,th);ctx.restore();drawEllipseArc(ctx,cx,cy-1,rx,ry,start+gap,start+ang-gap,'rgba(255,255,255,.20)',1.5);start+=ang});
