    const area=ctx.createLinearGradient(0,pad.t,0,pad.t+ch);area.addColorStop(0,colorAlpha(color,.32));area.addColorStop(.55,colorAlpha(color,.10));area.addColorStop(1,colorAlpha(color,0));ctx.beginPath();ctx.moveTo(pts[0].x,pad.t+ch);smoothPath(ctx,pts);ctx.lineTo(pts[pts.length-1].x,pad.t+ch);ctx.closePath();ctx.fillStyle=area;ctx.fill();
