function grouped(items,key,value){const m={};items.forEach(x=>{const k=x[key]||'Other';m[k]=(m[k]||0)+num(typeof value==='function'?value(x):x[value])});return Object.entries(m).map(([label,value])=>({label,value})).sort((a,b)=>b.value-a.value)}
function decorateAdvancedKpis(){const icons={'income':'↗','expense':'↘','profit':'◈','produced':'✂','ready':'✓','order':'▤','card':'♢','wallet':'▣','commission':'%','employee':'◎','salary':'▦','attendance':'◉','budget':'▥','invoice':'#','item':'◇','overtime':'⌁','transaction':'↔','due':'!','active':'●','warning':'!'};document.querySelectorAll('.kpi-card').forEach((card,idx)=>{if(card.dataset.advanced)return;card.dataset.advanced='1';const label=(card.querySelector('.kpi-label')?.textContent||'').toLowerCase();const key=Object.keys(icons).find(k=>label.includes(k));const icon=document.createElement('span');icon.className='kpi-icon';icon.textContent=icons[key]||'◆';card.prepend(icon);const spark=document.createElement('span');spark.className='kpi-spark';const points=[6,12,9,17,14,22,18,26].map((y,i)=>`${i*14},${30-y-(idx%3)*2}`).join(' ');spark.innerHTML=`<svg viewBox="0 0 100 32" preserveAspectRatio="none"><polyline points="${points}" fill="none" stroke="currentColor" stroke-width="2"/></svg>`;card.append(spark)})}
