function renderDashboardAdvanced(){const d=state.dashboard;if(!d)return;const c=d.current||{};if(d.can_see_finance){drawDonutAdvanced('profitDonutChart',[{label:'Net Profit',value:Math.max(0,num(c.profit)),color:ADVANCED_COLORS[2]},{label:'Operating Cost',value:num(c.expenses),color:ADVANCED_COLORS[1]}],{center:moneyValue(c.profit),sub:'Net Profit',moneyValues:true});drawDonutAdvanced('branchRevenueDonutChart',(d.branches||[]).map((x,i)=>({label:x.branch,value:num(x.income),color:ADVANCED_COLORS[i]})),{center:moneyValue((d.branches||[]).reduce((a,x)=>a+num(x.income),0)),sub:'Revenue',moneyValues:true})}drawDonutAdvanced('ordersPulseChart',[{label:'Pending',value:c.pending_orders,color:ADVANCED_COLORS[0]},{label:'Ready',value:c.ready_orders,color:ADVANCED_COLORS[2]},{label:'Overdue',value:c.overdue_orders,color:ADVANCED_COLORS[4]},{label:'Delivered',value:c.delivered_orders,color:ADVANCED_COLORS[1]}],{center:compactValue(num(c.pending_orders)+num(c.ready_orders)+num(c.overdue_orders)+num(c.delivered_orders)),sub:'Orders'});drawLineAdvanced('productionMomentumChart',(d.monthly||[]).map(x=>x.month.split(' ')[0]),[{label:'Produced',values:(d.monthly||[]).map(x=>num(x.ready_pcs)),color:ADVANCED_COLORS[0]}]);const topBranch=(d.branches||[]).slice().sort((a,b)=>num(b.income)-num(a.income))[0];setHighlights([{icon:'◈',label:'Profit Margin',value:pct(c.profit,c.income),note:'Current month-to-date'},{icon:'⌂',label:'Top Branch',value:topBranch?.branch||'—',note:topBranch?money(topBranch.income):'No data'},{icon:'✓',label:'Order Completion',value:pct(c.delivered_orders,num(c.pending_orders)+num(c.ready_orders)+num(c.overdue_orders)+num(c.delivered_orders)),note:'Delivered share'},{icon:'♢',label:'Active Cards',value:String(num(c.active_membership_cards)),note:`${num(c.expiring_membership_cards)} expiring soon`}])}
function renderOrdersAdvanced(){const rows=state.orders.orders||[];drawDonutAdvanced('orderStatusChart',grouped(rows,'status',()=>1).map((x,i)=>({...x,color:ADVANCED_COLORS[i]})),{center:String(rows.length),sub:'Orders'});const branch=grouped(rows,'branch',()=>1);drawBarAdvanced('orderBranchChart',branch.map(x=>x.label),[{label:'Orders',values:branch.map(x=>x.value),color:ADVANCED_COLORS[0]}],{horizontal:true});drawDonutAdvanced('orderCollectionChart',[{label:'Advance Received',value:rows.reduce((a,x)=>a+num(x.advance_amount),0),color:ADVANCED_COLORS[2]},{label:'Outstanding Balance',value:rows.reduce((a,x)=>a+num(x.balance_amount),0),color:ADVANCED_COLORS[4]}],{center:moneyValue(rows.reduce((a,x)=>a+num(x.advance_amount),0)),sub:'Collected',moneyValues:true})}
function renderMembershipAdvanced(){const cards=state.membership.cards||[];const plan=grouped(cards,'plan_name',()=>1);drawDonutAdvanced('membershipPlanChart',plan.map((x,i)=>({...x,color:ADVANCED_COLORS[i]})),{center:String(cards.length),sub:'Cards'});const wallet=grouped(cards,'plan_name','current_balance');drawBarAdvanced('membershipWalletChart',wallet.map(x=>x.label),[{label:'Wallet',values:wallet.map(x=>x.value),color:ADVANCED_COLORS[0]}],{horizontal:true,moneyValues:true});const agents=(state.commissions.rows||[]).slice(0,7);drawBarAdvanced('membershipAgentChart',agents.map(x=>x.sales_agent),[{label:'Commission',values:agents.map(x=>num(x.total_commission)),color:ADVANCED_COLORS[2]}],{horizontal:true,moneyValues:true})}
function renderProductionAdvanced(){const rows=state.production.summary||[];const stages=[['Cutting','cutting'],['Body','body'],['Joint','joint_side'],['Full Body','full_body_produced'],['Daraz','daraz'],['VIP Design','vip_design'],['Button','button'],['Alteration','alteration'],['Iron','iron'],['Ready',null]].map(([label,key])=>({label,value:key?rows.reduce((a,x)=>a+num(x[key]),0):num(state.production.ready_total)}));const max=Math.max(1,...stages.map(x=>x.value));const flow=$('productionStageFlow');if(flow)flow.innerHTML=stages.map((x,i)=>{const pc=Math.round(x.value/max*100);return `<div class="stage-card"><span class="stage-icon">${['✂','◫','⌒','✓','∪','♛','⊙','⌁','▱','◆'][i]}</span><strong>${x.label}</strong><b>${compactValue(x.value)} pcs</b><div class="stage-ring" style="--p:${pc}"><span>${pc}%</span></div><small>${pc>=80?'Strong Output':pc>=50?'In Progress':'Needs Focus'}</small></div>${i<stages.length-1?'<span class="stage-arrow">›</span>':''}`}).join('');const top=rows.slice().sort((a,b)=>num(b.total_pcs_produced)-num(a.total_pcs_produced)).slice(0,8);drawBarAdvanced('productionEmployeeChart',top.map(x=>x.employee),[{label:'Produced',values:top.map(x=>num(x.total_pcs_produced)),color:ADVANCED_COLORS[0]}],{horizontal:true});drawDonutAdvanced('productionMixChart',stages.filter(x=>!['Full Body','Ready'].includes(x.label)&&x.value>0).map((x,i)=>({...x,color:ADVANCED_COLORS[i]})),{center:compactValue(stages.reduce((a,x)=>a+x.value,0)),sub:'Activity'});const lb=$('productionLeaderboard');if(lb)lb.innerHTML=top.slice(0,5).map((x,i)=>`<div class="leaderboard-row"><span class="rank-badge rank-${i+1}">${i+1}</span><div><strong>${esc(x.employee)}</strong><small>${esc(x.branch)}</small></div><b>${compactValue(x.total_pcs_produced)} pcs</b><em>${num(x.ot_hours).toFixed(1)} OT</em></div>`).join('')||'<div class="empty-chart-note">No production data</div>'}
function renderFinanceAdvanced(){const rows=state.finance||[];const expenses=grouped(rows.filter(x=>x.type==='Expense'),'category','amount');drawDonutAdvanced('financeExpenseChart',expenses.slice(0,7).map((x,i)=>({...x,color:ADVANCED_COLORS[i]})),{center:moneyValue(expenses.reduce((a,x)=>a+x.value,0)),sub:'Expenses',moneyValues:true});const methods=grouped(rows,'payment_method','amount');drawDonutAdvanced('financePaymentChart',methods.map((x,i)=>({...x,color:ADVANCED_COLORS[i]})),{center:moneyValue(methods.reduce((a,x)=>a+x.value,0)),sub:'Transactions',moneyValues:true});const branches=grouped(rows.filter(x=>x.type==='Income'),'branch','amount');drawBarAdvanced('financeBranchChart',branches.map(x=>x.label),[{label:'Income',values:branches.map(x=>x.value),color:ADVANCED_COLORS[0]}],{horizontal:true,moneyValues:true})}
function renderSalesAdvanced(){const rows=state.posSales.sales||[];const byDate={};rows.forEach(x=>{const d=String(x.sale_datetime||'').slice(0,10);byDate[d]=(byDate[d]||0)+num(x.total_amount)});const dates=Object.keys(byDate).sort();drawLineAdvanced('salesTrendChart',dates.map(x=>x.slice(5)),[{label:'Sales',values:dates.map(x=>byDate[x]),color:ADVANCED_COLORS[0]}],{moneyValues:true});const status=grouped(rows,'payment_status','total_amount');drawDonutAdvanced('salesStatusChart',status.map((x,i)=>({...x,color:[ADVANCED_COLORS[2],ADVANCED_COLORS[0],ADVANCED_COLORS[4]][i]||ADVANCED_COLORS[i]})),{center:moneyValue(rows.reduce((a,x)=>a+num(x.total_amount),0)),sub:'Sales',moneyValues:true});const customers=grouped(rows,x=>x.customer_name||'Walk-in','total_amount');const cm={};rows.forEach(x=>{const k=x.customer_name||'Walk-in';cm[k]=(cm[k]||0)+num(x.total_amount)});const top=Object.entries(cm).map(([label,value])=>({label,value})).sort((a,b)=>b.value-a.value).slice(0,7);drawBarAdvanced('salesCustomerChart',top.map(x=>x.label),[{label:'Sales',values:top.map(x=>x.value),color:ADVANCED_COLORS[1]}],{horizontal:true,moneyValues:true})}
function renderEmployeesAdvanced(){const rows=state.employees||[];const top=rows.slice().sort((a,b)=>num(b.ready_pcs)-num(a.ready_pcs)).slice(0,8);drawBarAdvanced('employeeOutputChart',top.map(x=>x.name),[{label:'Produced',values:top.map(x=>num(x.ready_pcs)),color:ADVANCED_COLORS[0]}],{horizontal:true});const branches=grouped(rows,'branch',()=>1);drawDonutAdvanced('employeeBranchChart',branches.map((x,i)=>({...x,color:ADVANCED_COLORS[i]})),{center:String(rows.length),sub:'Employees'});const lb=$('employeeLeaderboard');if(lb)lb.innerHTML=top.slice(0,5).map((x,i)=>{const ach=num(x.monthly_target)?num(x.ready_pcs)/num(x.monthly_target)*100:0;return `<div class="leaderboard-row"><span class="rank-badge rank-${i+1}">${i+1}</span><div><strong>${esc(x.name)}</strong><small>${esc(x.role)} · ${esc(x.branch)}</small></div><b>${compactValue(x.ready_pcs)} pcs</b><em>${ach.toFixed(1)}%</em></div>`}).join('')||'<div class="empty-chart-note">No employee data</div>'}
function renderPayrollAdvanced(){if(!has('payroll_read'))return;const rows=state.payroll.rows||[];const comp=[{label:'Basic Salary',value:rows.reduce((a,x)=>a+num(x.basic_salary),0),color:ADVANCED_COLORS[1]},{label:'Commission',value:rows.reduce((a,x)=>a+num(x.commission),0),color:ADVANCED_COLORS[0]},{label:'Bonus',value:rows.reduce((a,x)=>a+num(x.bonus),0),color:ADVANCED_COLORS[2]},{label:'OT & Allowance',value:rows.reduce((a,x)=>a+num(x.overtime_amount)+num(x.other_allowance),0),color:ADVANCED_COLORS[3]}];drawDonutAdvanced('payrollCompositionChart',comp,{center:moneyValue(rows.reduce((a,x)=>a+num(x.net_salary),0)),sub:'Net Payroll',moneyValues:true});const status=grouped(state.attendance.rows||[],'status',()=>1);drawDonutAdvanced('attendanceMixChart',status.map((x,i)=>({...x,color:ADVANCED_COLORS[i]})),{center:String((state.attendance.rows||[]).length),sub:'Entries'});const bm={};rows.forEach(x=>bm[x.branch]=(bm[x.branch]||0)+num(x.net_salary));const b=Object.entries(bm).map(([label,value])=>({label,value}));drawBarAdvanced('payrollBranchChart',b.map(x=>x.label),[{label:'Net Payroll',values:b.map(x=>x.value),color:ADVANCED_COLORS[0]}],{horizontal:true,moneyValues:true})}
function renderBudgetAdvanced(){const d=state.budget.overview;if(!d)return;const rows=(d.rows||[]).filter(x=>x.active!==false).slice(0,9);drawBarAdvanced('budgetVarianceChart',rows.map(x=>x.category),[{label:'Budget',values:rows.map(x=>num(x.budget)),color:ADVANCED_COLORS[0]},{label:'Actual',values:rows.map(x=>num(x.actual)),color:ADVANCED_COLORS[1]}],{moneyValues:true});const s=d.summary||{};drawDonutAdvanced('budgetUtilizationChart',[{label:'Used',value:num(s.actual_expense),color:ADVANCED_COLORS[4]},{label:'Remaining',value:Math.max(0,num(s.total_budget)-num(s.actual_expense)),color:ADVANCED_COLORS[2]}],{center:`${num(s.total_budget)?Math.min(999,num(s.actual_expense)/num(s.total_budget)*100).toFixed(1):'0.0'}%`,sub:'Utilized',moneyValues:true});const b=d.branch_summary||[];drawBarAdvanced('budgetBranchProfitChart',b.map(x=>x.branch),[{label:'Profit',values:b.map(x=>Math.max(0,num(x.profit))),color:ADVANCED_COLORS[2]}],{horizontal:true,moneyValues:true})}
function renderAllAdvanced(){decorateAdvancedKpis();const active=document.querySelector('.page.active')?.id;if(active==='dashboard')renderDashboardAdvanced();if(active==='orders')renderOrdersAdvanced();if(active==='membership')renderMembershipAdvanced();if(active==='production')renderProductionAdvanced();if(active==='financials')renderFinanceAdvanced();if(active==='posSales')renderSalesAdvanced();if(active==='employees')renderEmployeesAdvanced();if(active==='payroll')renderPayrollAdvanced();if(active==='budget')renderBudgetAdvanced()}
/* Phase 3.7 — Executive Dashboard Home: hero, business health, alerts center, quick actions */
function T(k){return window.I18N?I18N.t(k):k}
function clampScore(n,lo,hi){return Math.max(lo,Math.min(hi,n))}
function execActiveBranch(){return (state.dashboard&&state.dashboard.branch)||$('globalBranch').value||'All'}
function execDateLabel(){try{const l=window.I18N?I18N.getLanguage():'en';return new Date().toLocaleDateString(l==='ar'?'ar':'en-GB',{weekday:'long',day:'numeric',month:'long',year:'numeric'})}catch(e){return new Date().toDateString()}}
function execSevRank(s){return s==='critical'?3:s==='warning'?2:s==='info'?1:0}
function execHealthLabel(s){return s>=80?'Excellent':s>=65?'Healthy':s>=50?'Stable':s>=35?'Needs Attention':'Critical'}
function execHealthClass(s){return s>=65?'good':s>=50?'ok':s>=35?'warn':'bad'}
function renderExecHero(){const el=$('execHero');if(!el)return;const branch=execActiveBranch();const branchLabel=branch==='All'?T('All Branches'):branch;const company=(_companyName||'').trim();const title=company?esc(company):T('Executive Business Snapshot');const titleAttr=company?' data-no-i18n':'';const sub=company?`<p class="exec-hero-sub">${T('Executive Business Snapshot')}</p>`:'';el.innerHTML=`<div class="exec-hero-main"><span class="eyebrow">${T('EXECUTIVE OVERVIEW')}</span><h2 class="exec-hero-greet"${titleAttr}>${title}</h2>${sub}</div><div class="exec-hero-meta"><div class="exec-hero-chip"><span>${T('Active Branch')}</span><strong>${esc(branchLabel)}</strong></div><div class="exec-hero-chip"><span>${T('Date')}</span><strong class="exec-hero-date" data-no-i18n>${esc(execDateLabel())}</strong></div></div>`}
function computeExecHealth(){const d=state.dashboard;if(!d)return null;const c=d.current||{};const parts=[];if(d.can_see_finance){const income=num(c.income),profit=num(c.profit);const margin=income?profit/income:0;parts.push({key:'financial',label:'Financial',score:clampScore(Math.round(margin/0.25*100),0,100),detail:pct(profit,income)+' '+T('margin')})}{const hist=(d.monthly||[]).slice(0,-1).map(m=>num(m.ready_pcs)).filter(v=>v>0);const avg=hist.length?hist.reduce((a,b)=>a+b,0)/hist.length:0;const cur=Math.max(num(c.ready_pcs),num(c.calculated_stage_pcs));parts.push({key:'production',label:'Production',score:avg?clampScore(Math.round(cur/avg*100),0,100):(cur>0?70:0),detail:compactValue(cur)+' '+T('pcs')})}{const total=num(c.pending_orders)+num(c.ready_orders)+num(c.overdue_orders)+num(c.delivered_orders);const overdue=num(c.overdue_orders);const delivered=num(c.delivered_orders);parts.push({key:'orders',label:'Orders',score:total?clampScore(Math.round(delivered/total*60+(1-overdue/total)*40),0,100):0,detail:overdue?overdue+' '+T('overdue'):T('On track')})}{const s=(state.notifications&&state.notifications.summary)||{};const crit=num(s.critical),warn=num(s.warning);parts.push({key:'alerts',label:'Alerts',score:clampScore(100-crit*14-warn*5,0,100),detail:crit?crit+' '+T('critical'):(warn?warn+' '+T('warnings'):T('All clear'))})}const overall=parts.length?Math.round(parts.reduce((a,p)=>a+p.score,0)/parts.length):0;return {overall,parts}}
function renderExecHealth(){const band=$('execHealthBand');if(!band)return;const h=computeExecHealth();if(!h){band.innerHTML='';return}const chip=$('execHealthChip');if(chip)chip.textContent=T(execHealthLabel(h.overall));const icons={financial:'◈',production:'✂',orders:'◇',alerts:'◉'};band.innerHTML=`<div class="health-gauge health-${execHealthClass(h.overall)}" style="--p:${h.overall}"><div class="health-gauge-inner"><strong>${h.overall}</strong><small>${T(execHealthLabel(h.overall))}</small></div></div><div class="health-parts">${h.parts.map(p=>`<div class="health-part health-${execHealthClass(p.score)}"><div class="health-part-top"><span class="health-part-icon">${icons[p.key]||'◆'}</span><span class="health-part-label">${T(p.label)}</span><b>${p.score}</b></div><div class="health-bar"><i style="width:${p.score}%"></i></div><small>${esc(p.detail)}</small></div>`).join('')}</div>`}
function renderExecAlerts(){const panel=$('execAlertsList');if(!panel)return;const n=state.notifications||{};const s=n.summary||{};const sumEl=$('execAlertsSummary');if(sumEl){const cards=[['critical',T('Critical'),num(s.critical)],['warning',T('Warnings'),num(s.warning)],['info',T('Unread'),num(s.unread)]];sumEl.innerHTML=cards.map(c=>`<div class="exec-alert-stat ${c[0]}"><i class="alert-dot ${c[0]}"></i><div><strong>${c[2]}</strong><span>${c[1]}</span></div></div>`).join('')}const alerts=(n.alerts||[]).slice().sort((a,b)=>execSevRank(b.severity)-execSevRank(a.severity)).slice(0,5);panel.innerHTML=alerts.length?alerts.map(a=>`<button class="exec-alert-row ${a.read?'read':''}" onclick="handleAlertClick('${encodeURIComponent(a.key)}','${a.target_page}')"><i class="alert-dot ${a.severity}"></i><span><strong>${esc(a.title)}</strong><small>${esc(a.branch)} · ${esc(a.message)}</small></span><em class="alert-severity ${a.severity}">${a.severity}</em></button>`).join(''):`<div class="empty-alerts">${T('No current alerts.')}</div>`}
function renderExecQuickActions(){const el=$('execQuickActions');if(!el)return;const actions=[{icon:'＋',label:'Add Order',perm:'orders_read',cb:'execAddOrder()'},{icon:'⚙',label:'Open Production',perm:'production_read',page:'production'},{icon:'◈',label:'Open Financials',perm:'finance_read',page:'financials'},{icon:'▤',label:'Open Reports',perm:'reports',page:'reports'},{icon:'♙',label:'Company Settings',perm:'dashboard',page:'settings'}];el.innerHTML=actions.filter(a=>has(a.perm)).map(a=>`<button class="exec-action-card" onclick="${a.cb||`execGoto('${a.page}')`}"><span class="exec-action-icon">${a.icon}</span><strong>${T(a.label)}</strong></button>`).join('')}
