function fillFinanceCategoryOptions(type=null,preferred=''){
  const form=$('financeForm');if(!form||!form.elements.category)return;
  const selectedType=type||form.elements.type.value||'Income';
  const select=$('financeEntryCategory');
  const income=['Shop Sales','Membership Cards','Other Income'];
  const expense=(state.budget.categories||[]).filter(c=>c.active).map(c=>c.name);
  const options=selectedType==='Expense'?expense:income;
  select.innerHTML=options.map(x=>`<option value="${x}">${x}</option>`).join('');
  if(preferred&&!options.includes(preferred)){select.insertAdjacentHTML('beforeend',`<option value="${preferred}">${preferred}</option>`)}
  if(preferred)select.value=preferred;
}
if($('financeForm'))$('financeForm').elements.type.onchange=e=>fillFinanceCategoryOptions(e.target.value);

async function loadBudgetCategories(){
  if(!has('budget_read'))return;
  const d=await api('/api/budget/categories');state.budget.categories=d.categories||[];renderBudgetCategoryManager();fillFinanceCategoryOptions();
}
async function loadBudget(){
  if(!has('budget_read'))return;
  const p=new URLSearchParams({branch:$('budgetBranch').value||'All',month:getMonthValue('budgetMonth')});
  try{const d=await api('/api/budget?'+p);state.budget.overview=d;state.budget.categories=d.categories||state.budget.categories;renderBudget();fillFinanceCategoryOptions()}
  catch(err){toast(err.message,true)}
}
function budgetStatusClass(status){return status==='Over Budget'||status==='No Budget'?'negative':status==='Warning'?'warning':'positive'}
function renderBudget(){
  const d=state.budget.overview;if(!d)return;const s=d.summary||{},editable=has('budget_write')&&d.branch!=='All'&&!d.locked;
  $('budgetStatusPill').textContent=d.status+(d.locked?' · Locked':'');$('budgetStatusPill').className='budget-status-pill '+(d.locked?'locked':'');
  const cards=[['Expense Budget',money(s.total_budget),'Monthly approved limit'],['Actual Expenses',money(s.actual_expense),`${pct(s.actual_expense,s.total_budget)} used`],['Remaining Budget',money(s.remaining_budget),`${s.over_budget_categories||0} categories need attention`],['Income Achievement',`${num(s.income_achievement).toFixed(1)}%`,`${money(s.actual_income)} of ${money(s.income_target)}`],['Actual Profit',money(s.actual_profit),`${num(s.actual_margin).toFixed(1)}% margin`],['Projected Profit',money(s.projected_profit),`${num(s.projected_margin).toFixed(1)}% projected margin`],['Required Daily Income',money(s.required_daily_income),'To achieve monthly income target'],['Budget Status',d.status,d.branch==='All'?'Consolidated view':d.branch]];
  $('budgetKpis').innerHTML=cards.map(c=>`<div class="kpi-card"><div class="kpi-label">${c[0]}</div><div class="kpi-value">${c[1]}</div><div class="kpi-note">${c[2]}</div></div>`).join('');
  $('budgetShopTarget').value=num(d.target.shop_sales_target);$('budgetMembershipTarget').value=num(d.target.membership_target);$('budgetOtherTarget').value=num(d.target.other_income_target);$('budgetProfitMargin').value=num(d.target.min_profit_margin);$('budgetTargetNotes').value=d.target.notes||'';$('budgetPlanNotes').value=d.plan_notes||'';
  document.querySelectorAll('.budget-input').forEach(x=>x.disabled=!editable);
  $('saveBudgetBtn').disabled=!editable;$('budgetRevisionReason').disabled=!editable;$('budgetPlanNotes').disabled=!editable;
  $('budgetEditHint').textContent=d.branch==='All'?'Consolidated view. Select one branch to edit.':d.locked?'Budget is locked. Owner/Admin must unlock it.':'Amounts, warning limits and notes are editable.';
  $('budgetTableBody').innerHTML=(d.rows||[]).map(r=>`<tr data-category-id="${r.category_id||''}"><td><strong>${r.category}</strong>${r.active?'':' <small class="status-badge inactive">Inactive</small>'}</td><td>${editable&&r.category_id?`<input class="table-input budget-amount" type="number" min="0" step="0.001" value="${r.budget}">`:money(r.budget)}</td><td>${money(r.actual)}</td><td class="${r.remaining<0?'status-expense':'status-profit'}">${money(r.remaining)}</td><td>${num(r.used_percent).toFixed(1)}%</td><td>${editable&&r.category_id?`<input class="table-input budget-warning" type="number" min="1" max="100" step="1" value="${r.warning_percent}">`:`${r.warning_percent}%`}</td><td><span class="status-badge ${budgetStatusClass(r.status)}">${r.status}</span></td><td>${editable&&r.category_id?`<input class="table-input budget-note" value="${String(r.notes||'').replaceAll('"','&quot;')}">`:(r.notes||'—')}</td></tr>`).join('')||'<tr><td colspan="8">No categories available.</td></tr>';
  $('budgetForecast').innerHTML=[['Elapsed days',`${s.elapsed_days||0} / ${s.days_in_month||0}`],['Projected income',money(s.projected_income)],['Projected expenses',money(s.projected_expense)],['Projected profit',money(s.projected_profit)],['Projected margin',`${num(s.projected_margin).toFixed(1)}%`],['Target profit margin',`${num(d.target.min_profit_margin).toFixed(1)}%`]].map(x=>`<div><span>${x[0]}</span><strong>${x[1]}</strong></div>`).join('');
  $('budgetBranchTableBody').innerHTML=(d.branch_summary||[]).map(r=>`<tr><td>${r.branch}</td><td>${money(r.income_target)}</td><td>${money(r.actual_income)}</td><td>${money(r.expense_budget)}</td><td>${money(r.actual_expense)}</td><td class="${r.profit>=0?'status-profit':'status-expense'}">${money(r.profit)}</td></tr>`).join('');
  $('budgetRevisionBody').innerHTML=(d.revisions||[]).map(r=>`<tr><td>${r.changed_at}</td><td>${r.branch}</td><td>${r.category_name}</td><td>${money(r.old_amount)}</td><td>${money(r.new_amount)}</td><td>${r.old_warning_percent}% → ${r.new_warning_percent}%</td><td>${r.reason||'—'}</td><td>${r.changed_by}</td></tr>`).join('')||'<tr><td colspan="8">No revisions recorded for this period.</td></tr>';
}
$('applyBudgetFilter').onclick=loadBudget;$('budgetBranch').onchange=loadBudget;$('budgetMonth').onchange=loadBudget;
function collectBudgetPlanPayload(){
  const d=state.budget.overview;
  if(!d||d.branch==='All')throw new Error('Select one branch before saving');
  const items=[...$('budgetTableBody').querySelectorAll('tr[data-category-id]')].map(tr=>({
    category_id:Number(tr.dataset.categoryId),
    budget_amount:Number(tr.querySelector('.budget-amount')?.value||0),
    warning_percent:Number(tr.querySelector('.budget-warning')?.value||80),
    notes:tr.querySelector('.budget-note')?.value||''
  })).filter(x=>x.category_id);
  return {
    month:getMonthValue('budgetMonth'),
    branch:$('budgetBranch').value,
    items,
    targets:{
      shop_sales_target:Number($('budgetShopTarget').value||0),
      membership_target:Number($('budgetMembershipTarget').value||0),
      other_income_target:Number($('budgetOtherTarget').value||0),
      min_profit_margin:Number($('budgetProfitMargin').value||20),
      notes:$('budgetTargetNotes').value
    },
    notes:$('budgetPlanNotes').value,
    revision_reason:$('budgetRevisionReason').value
  };
}
async function saveCurrentBudget({reload=true,notify=true}={}){
  const body=collectBudgetPlanPayload();
  await api('/api/budget/plan',{method:'POST',body});
  $('budgetRevisionReason').value='';
  if(reload)await loadBudget();
  if(notify)toast('Budget saved successfully');
  return body;
}
$('saveBudgetBtn').onclick=async()=>{try{await saveCurrentBudget()}catch(err){toast(err.message,true)}};
function previousMonth(month){const [y,m]=month.split('-').map(Number),d=new Date(y,m-2,1);return `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}`}
$('copyBudgetBtn').onclick=()=>{const target=getMonthValue('budgetMonth'),source=previousMonth(target),branch=$('budgetBranch').value;confirmAction('Copy previous month budget?',`Copy ${source} budget into ${target} for ${branch}? Existing unlocked target values will be replaced.`,async()=>{const d=await api('/api/budget/copy',{method:'POST',body:{source_month:source,target_month:target,branch}});await loadBudget();toast(`${d.copied} branch budget copied`)})};
async function changeBudgetStatus(status,button){
  const branch=$('budgetBranch').value,month=getMonthValue('budgetMonth');
  if(branch==='All')return toast('Select one branch first',true);
  const original=button.textContent;
  button.disabled=true;button.textContent='Saving…';
  try{
    // When editable fields are visible, persist all current values before approval/locking/closing.
    // This prevents unsaved inputs from reverting to zero after the status refresh.
    const hasEditableBudgetInputs=!!$('budgetTableBody').querySelector('.budget-amount');
    if(status!=='Draft'&&hasEditableBudgetInputs){
      await saveCurrentBudget({reload:false,notify:false});
    }
    const result=await api('/api/budget/status',{method:'POST',body:{month,branch,status}});
    await loadBudget();
    if(result.status==='Approved')toast('Budget saved and approved');
    else if(result.locked)toast(result.status==='Closed'?'Budget saved and month closed':'Budget saved, approved and locked');
    else toast(`Budget status changed to ${result.status}`);
  }catch(err){toast(err.message,true)}finally{button.disabled=false;button.textContent=original}
}
document.querySelectorAll('[data-budget-status]').forEach(btn=>btn.onclick=()=>{
  const status=btn.dataset.budgetStatus;
  const title=status==='Locked'?'Approve and lock budget?':status==='Approved'?'Approve budget?':status==='Closed'?'Close this budget month?':`Change budget to ${status}?`;
  const message=status==='Locked'
    ?'All currently entered budget amounts will be saved first. The budget will then be approved and editing disabled until Owner/Admin unlocks it.'
    :status==='Approved'
      ?'All currently entered budget amounts will be saved first and then approved.'
      :status==='Closed'
        ?'All currently entered budget amounts will be saved first and the month will then be closed.'
        :'The selected branch and month will return to Draft and become editable.';
  confirmAction(title,message,()=>changeBudgetStatus(status,btn));
});
$('manageBudgetCategoriesBtn').onclick=async()=>{await loadBudgetCategories();resetBudgetCategoryForm();openModal('budgetCategoryModal')};
function renderBudgetCategoryManager(){$('budgetCategoryTableBody').innerHTML=(state.budget.categories||[]).map(c=>`<tr><td>${c.name}</td><td>${c.default_warning_percent}%</td><td><span class="status-badge ${c.active?'positive':'inactive'}">${c.active?'Active':'Inactive'}</span></td><td><button class="link-btn" onclick="editBudgetCategory(${c.id})">Edit</button></td></tr>`).join('')}
function resetBudgetCategoryForm(){const f=$('budgetCategoryForm');f.reset();f.elements.id.value='';f.elements.default_warning_percent.value=80;f.elements.active.checked=true}
$('clearBudgetCategoryForm').onclick=resetBudgetCategoryForm;
window.editBudgetCategory=id=>{const c=state.budget.categories.find(x=>x.id===id);if(!c)return;const f=$('budgetCategoryForm');f.elements.id.value=c.id;f.elements.name.value=c.name;f.elements.default_warning_percent.value=c.default_warning_percent;f.elements.active.checked=!!c.active};
$('budgetCategoryForm').onsubmit=async e=>{e.preventDefault();const f=new FormData(e.target),id=f.get('id'),body={name:f.get('name'),default_warning_percent:Number(f.get('default_warning_percent')),active:e.target.elements.active.checked};try{await api(id?`/api/budget/categories/${id}`:'/api/budget/categories',{method:id?'PUT':'POST',body});await loadBudgetCategories();resetBudgetCategoryForm();await loadBudget();toast(id?'Category updated':'Category added')}catch(err){toast(err.message,true)}};
